// Fill missing languages with English fallback
["nl","ja","ko","zh","ru"].forEach(l => { T[l] = T[l] || { ...T.en }; });

function detectLang() { const b = (navigator.language || "en").slice(0, 2).toLowerCase(); return T[b] ? b : "en"; }

// ─── State & Storage ─────────────────────────────────
const DEFAULT_STATE = { step:1, appName:"", slug:"", slugManuallyEdited:false, ownerEmail:"", geminiHasKey:null, geminiApiKey:"", geminiModel:"gemini-2.5-flash", showModelOptions:false, authorizedUsers:[], fbProjectCreated:false, fbBlazeUpgraded:false, fbBudgetAlert:false, svcAuth:false, svcFirestore:false, svcHostingWeb:false, svcFunctions:false, fbApiKey:"", fbAuthDomain:"", fbProjectId:"", fbStorageBucket:"", fbMessagingSenderId:"", fbAppId:"", cliInstalled:false, cliLoggedIn:false, cliProjectLinked:false, cliSecretManagerEnabled:false, cliSecretSaved:false };

function toSlug(n) { return n.toLowerCase().replace(/[^a-z0-9]+/g,"-").replace(/^-+|-+$/g,"").slice(0,30); }
const SLUG_RE=/^[a-z][a-z0-9-]{2,28}[a-z0-9]$/,EMAIL_RE=/^[^\s@]+@[^\s@]+\.[^\s@]+$/;
async function loadState(){try{const r=await window.storage.get(STORAGE_KEY);return r?JSON.parse(r.value):null}catch{return null}}
async function saveState(s){try{await window.storage.set(STORAGE_KEY,JSON.stringify(s))}catch{}}
async function clearState(){try{await window.storage.delete(STORAGE_KEY)}catch{}}
async function loadLang(){try{const r=await window.storage.get(LANG_KEY);return r?r.value:null}catch{return null}}
async function saveLang(l){try{await window.storage.set(LANG_KEY,l)}catch{}}
function tryCopy(t){try{if(navigator?.clipboard?.writeText){navigator.clipboard.writeText(t).catch(()=>{});return true}}catch{}try{const a=document.createElement("textarea");a.value=t;a.setAttribute("readonly","");a.style.cssText="position:fixed;left:-9999px;opacity:0";document.body.appendChild(a);a.select();const ok=document.execCommand("copy");document.body.removeChild(a);if(ok)return true}catch{}return false}

// Firebase Console direct URLs
const fbUrl=(slug,path)=>`https://console.firebase.google.com/project/${slug}/${path}`;

// ─── UI Components ───────────────────────────────────
function ProgressBar({step}){const p=((step-1)/10)*100;return <div className="mb-6"><div className="flex items-center justify-between mb-1.5"><span className="text-xs text-zinc-400 font-mono">STEP {step} OF 11</span><span className="text-xs text-zinc-500">{Math.round(p)}%</span></div><div className="w-full h-1.5 bg-zinc-800 rounded-full overflow-hidden"><div className="h-full bg-blue-500 rounded-full transition-all duration-500" style={{width:`${p}%`}}/></div></div>}
function Tit({children}){return <><h1 className="text-2xl font-bold text-white mb-1">{children}</h1><div className="w-12 h-1 bg-blue-500 rounded mb-5"/></>}
function Inp({label,value,onChange,placeholder,error,type="text",mono=false,disabled=false}){return <div className="mb-3">{label&&<label className="block text-xs text-zinc-400 mb-1">{label}</label>}<input type={type} value={value} onChange={onChange} placeholder={placeholder} disabled={disabled} className={`w-full px-3 py-2 rounded-lg bg-zinc-800 text-white border ${error?"border-red-500":"border-zinc-700"} focus:outline-none focus:border-blue-500 disabled:opacity-50 ${mono?"font-mono text-sm":"text-sm"}`}/>{error&&<p className="text-red-400 text-xs mt-1">{error}</p>}</div>}
function Btn({children,onClick,v="primary",disabled=false,className=""}){const vs={primary:"bg-blue-600 hover:bg-blue-500 text-white",secondary:"bg-zinc-700 hover:bg-zinc-600 text-white",danger:"bg-red-900/60 hover:bg-red-800 text-red-200 border border-red-800/50",ghost:"bg-transparent hover:bg-zinc-800 text-zinc-400",success:"bg-emerald-700 hover:bg-emerald-600 text-white"};return <button onClick={onClick} disabled={disabled} className={`px-5 py-2.5 rounded-lg font-medium text-sm transition-all disabled:opacity-40 disabled:cursor-not-allowed cursor-pointer ${vs[v]||vs.primary} ${className}`}>{children}</button>}
function Rad({options,value,onChange}){return <div className="space-y-2">{options.map(o=><label key={o.value} className={`flex items-start gap-3 p-3 rounded-lg cursor-pointer border transition-all ${value===o.value?"border-blue-500 bg-blue-500/10":"border-zinc-700 bg-zinc-800/50 hover:border-zinc-600"}`}><input type="radio" checked={value===o.value} onChange={()=>onChange(o.value)} className="mt-0.5 accent-blue-500"/><span className="text-sm text-zinc-200">{o.label}</span></label>)}</div>}
function Toast({message,type="success"}){if(!message)return null;const c={success:"bg-emerald-900/80 border-emerald-700 text-emerald-200",error:"bg-red-900/80 border-red-700 text-red-200",info:"bg-blue-900/80 border-blue-700 text-blue-200"};return <div className={`mt-3 px-4 py-2 rounded-lg border text-sm text-center ${c[type]||c.info}`}>{message}</div>}
function Chk({checked,onChange,children}){return <label className={`flex items-start gap-3 p-3 rounded-lg cursor-pointer border transition-all ${checked?"border-emerald-600 bg-emerald-900/20":"border-zinc-700 bg-zinc-800/40"}`}><input type="checkbox" checked={checked} onChange={e=>onChange(e.target.checked)} className="mt-0.5 accent-emerald-500 w-4 h-4 flex-shrink-0"/><span className="text-sm text-zinc-300 leading-relaxed">{children}</span></label>}
function Nav({onBack,onNext,nextDisabled,nextLabel,t,showBack=true}){return <div className="flex gap-3 mt-6">{showBack&&<Btn v="ghost" onClick={onBack}>{t("back")}</Btn>}{onNext&&<Btn onClick={onNext} disabled={nextDisabled}>{nextLabel||t("next")}</Btn>}</div>}
function Row({label,value}){return <div className="flex justify-between px-4 py-2.5 text-sm border-b border-zinc-700/50 last:border-b-0"><span className="text-zinc-400">{label}</span><span className="text-white font-mono text-right break-all ml-4">{value}</span></div>}
function FbLink({slug,path,children}){return <a href={fbUrl(slug,path)} target="_blank" rel="noreferrer" className="text-blue-400 underline font-medium">{children}<span className="text-zinc-600 text-xs ml-0.5">↗</span></a>}

// Language selector
function LangSelect({lang,setLang}){return <select value={lang} onChange={e=>{setLang(e.target.value);saveLang(e.target.value)}} className="bg-zinc-800 text-zinc-400 border border-zinc-700 rounded px-2 py-1 text-xs cursor-pointer focus:outline-none">{Object.entries(LANGS).map(([k,v])=><option key={k} value={k}>{v}</option>)}</select>}

// ─── Steps ───────────────────────────────────────────
function S1({t,goTo}){return <div><Tit>{t("s1t")}</Tit><p className="text-zinc-300 mb-5 text-sm leading-relaxed">{t("s1d")}</p><div className="bg-zinc-800/60 border border-zinc-700/50 rounded-xl p-4 mb-5"><h3 className="text-xs font-semibold text-zinc-400 uppercase tracking-wider mb-2">{t("s1g")}</h3><ul className="space-y-1.5 text-sm text-zinc-400">{t("s1i").map(x=><li key={x} className="flex items-center gap-2"><span className="text-blue-400">→</span>{x}</li>)}</ul></div><p className="text-xs text-zinc-500 mb-6">{t("cost")}</p><Btn onClick={()=>goTo(2)}>{t("start")}</Btn></div>}

function S2({s,u,t,goTo}){const ne=s.appName.length>0&&s.appName.length<2?t("err_short"):"";const se=s.slug.length>0&&!SLUG_RE.test(s.slug)?t("err_slug"):"";const ok=s.appName.length>=2&&SLUG_RE.test(s.slug);return <div><Tit>{t("s2t")}</Tit><Inp label={t("s2n")} value={s.appName} placeholder="Family Assistant" error={ne} onChange={e=>{const v=e.target.value;u({appName:v,...(!s.slugManuallyEdited?{slug:toSlug(v)}:{})});}}/><Inp label={t("s2s")} value={s.slug} placeholder="family-assistant" error={se} mono onChange={e=>u({slug:e.target.value.toLowerCase(),slugManuallyEdited:true})}/>{s.slug&&<p className="text-sm text-zinc-400 mb-2 font-mono">{t("s2u")} <span className="text-blue-400">https://{s.slug}.web.app</span></p>}<p className="text-xs text-zinc-500 mt-3">{t("slug_warn")}</p><Nav onBack={()=>goTo(1)} onNext={()=>goTo(3)} nextDisabled={!ok} t={t}/></div>}

function S3({s,u,t,goTo}){const err=s.ownerEmail.length>0&&!EMAIL_RE.test(s.ownerEmail)?t("err_email"):"";const ok=EMAIL_RE.test(s.ownerEmail);return <div><Tit>{t("s3t")}</Tit><Inp label={t("s3l")} type="email" value={s.ownerEmail} placeholder="you@gmail.com" error={err} onChange={e=>u({ownerEmail:e.target.value})}/><div className="bg-zinc-800/60 border border-zinc-700/50 rounded-xl p-4 mt-3 text-sm text-zinc-400 space-y-1"><p className="text-zinc-300 mb-1">{t("s3a")}</p>{t("s3i").map(x=><p key={x}>• {x}</p>)}</div><Nav onBack={()=>goTo(2)} onNext={()=>{const au=s.authorizedUsers.length>0?[...s.authorizedUsers]:[];if(au.length===0||au[0].email!==s.ownerEmail.toLowerCase())au[0]={email:s.ownerEmail.toLowerCase(),role:"admin"};u({step:4,authorizedUsers:au})}} nextDisabled={!ok} t={t}/></div>}

function S4({s,u,t,goTo}){const ke=s.geminiHasKey==="yes"&&s.geminiApiKey.length>0&&(!s.geminiApiKey.startsWith("AIza")||s.geminiApiKey.length<30)?t("err_key"):"";const ok=s.geminiHasKey==="yes"&&s.geminiApiKey.startsWith("AIza")&&s.geminiApiKey.length>=30;return <div><Tit>{t("s4t")}</Tit><p className="text-sm text-zinc-400 mb-4">{t("s4d")}</p><Rad value={s.geminiHasKey} onChange={v=>u({geminiHasKey:v})} options={[{value:"yes",label:t("s4y")},{value:"no",label:t("s4n")}]}/>{s.geminiHasKey==="no"&&<div className="mt-3 bg-zinc-800/80 border border-zinc-700 rounded-xl p-4 text-sm text-zinc-300 space-y-2"><p>1. {t("s4g1")} <a href="https://aistudio.google.com/app/apikey" target="_blank" rel="noreferrer" className="text-blue-400 underline">Google AI Studio ↗</a></p><p>2. {t("s4g2")}</p><p>3. {t("s4g3")} (<code className="bg-zinc-700 px-1 rounded">AIza...</code>)</p><Btn v="secondary" className="mt-2" onClick={()=>u({geminiHasKey:"yes"})}>{t("s4h")}</Btn></div>}{s.geminiHasKey==="yes"&&<div className="mt-3"><Inp label="API Key" value={s.geminiApiKey} placeholder="AIza..." error={ke} mono onChange={e=>u({geminiApiKey:e.target.value})}/><p className="text-xs text-zinc-500 -mt-1 mb-3">{t("stored")}</p></div>}<button onClick={()=>u({showModelOptions:!s.showModelOptions})} className="mt-2 text-xs text-zinc-500 hover:text-zinc-300 cursor-pointer">{s.showModelOptions?"▾":"▸"} Model</button>{s.showModelOptions&&<select value={s.geminiModel} onChange={e=>u({geminiModel:e.target.value})} className="mt-2 w-full px-3 py-2 bg-zinc-800 text-white border border-zinc-700 rounded-lg text-sm">{[["gemini-2.5-flash","2.5 Flash (default, free)"],["gemini-2.5-pro","2.5 Pro (⚠️ requires paid billing)"],["gemini-3-flash","3 Flash (free)"],["gemini-3-pro","3 Pro (⚠️ requires paid billing)"]].map(([v,l])=><option key={v} value={v}>{l}</option>)}</select>}<Nav onBack={()=>goTo(3)} onNext={()=>goTo(5)} nextDisabled={!ok} t={t}/></div>}

function S5({s,u,t,goTo}){const[err,setErr]=useState("");const us=s.authorizedUsers,oe=s.ownerEmail.toLowerCase();useEffect(()=>{if(us.length===0&&oe)u({authorizedUsers:[{email:oe,role:"admin"}]});else if(us.length>0&&us[0].email!==oe&&oe){const c=[...us];c[0]={email:oe,role:"admin"};u({authorizedUsers:c})}},[oe]);const emails=us.map(x=>x.email.toLowerCase().trim());const dupes=new Set,seen=new Set;emails.forEach(e=>{if(seen.has(e)&&e)dupes.add(e);seen.add(e)});const valid=us.length>=1&&us.every((x,i)=>i===0||(EMAIL_RE.test(x.email)&&!dupes.has(x.email.toLowerCase().trim())));return <div><Tit>{t("s5t")}</Tit><p className="text-sm text-zinc-400 mb-4">{t("s5d")}</p><div className="space-y-2">{us.map((x,i)=>{const isO=i===0,isD=dupes.has(x.email.toLowerCase().trim())&&x.email,isI=!isO&&x.email.length>0&&!EMAIL_RE.test(x.email);return <div key={i} className="flex items-center gap-2"><input value={x.email} disabled={isO} placeholder="email@gmail.com" onChange={e=>{const c=[...us];c[i]={...c[i],email:e.target.value};u({authorizedUsers:c})}} className={`flex-1 px-3 py-2 rounded-lg bg-zinc-800 text-white border text-sm ${isD||isI?"border-red-500":"border-zinc-700"} focus:outline-none focus:border-blue-500 disabled:opacity-60 font-mono`}/><select value={x.role} disabled={isO} onChange={e=>{if(isO&&e.target.value!=="admin"){setErr(t("err_demote"));setTimeout(()=>setErr(""),3e3);return}const c=[...us];c[i]={...c[i],role:e.target.value};u({authorizedUsers:c})}} className="px-2 py-2 bg-zinc-800 text-white border border-zinc-700 rounded-lg text-sm disabled:opacity-60"><option value="admin">admin</option><option value="user">user</option></select>{isO?<span className="text-xs text-zinc-500 w-7 text-center">🔒</span>:<button onClick={()=>{u({authorizedUsers:us.filter((_,j)=>j!==i)})}} className="text-red-400 hover:text-red-300 w-7 text-center text-lg cursor-pointer">×</button>}</div>})}</div><button onClick={()=>u({authorizedUsers:[...us,{email:"",role:"user"}]})} className="mt-2 text-sm text-blue-400 hover:text-blue-300 cursor-pointer">{t("add_user")}</button><Toast message={err} type="error"/><Nav onBack={()=>goTo(4)} onNext={()=>goTo(6)} nextDisabled={!valid} t={t}/></div>}

function S6({s,t,goTo}){const admins=s.authorizedUsers.filter(x=>x.role==="admin").length;return <div><Tit>{t("s6t")}</Tit><p className="text-sm text-zinc-400 mb-4">{t("s6d")}</p><div className="bg-zinc-800/80 border border-zinc-700 rounded-xl overflow-hidden mb-4"><Row label={t("lb_app")} value={s.appName}/><Row label={t("lb_slug")} value={s.slug}/><Row label={t("lb_url")} value={`https://${s.slug}.web.app`}/><Row label={t("lb_owner")} value={s.ownerEmail}/><Row label={t("lb_gemini")} value={`${s.geminiModel} · AIza...${s.geminiApiKey.slice(-4)}`}/><Row label={t("lb_users")} value={`${s.authorizedUsers.length} (${admins} admin)`}/></div><Nav onBack={()=>goTo(5)} onNext={()=>goTo(7)} nextLabel={t("looks_good")} t={t}/></div>}

function S7({s,u,t,goTo}){const ok=s.fbProjectCreated&&s.fbBlazeUpgraded&&s.fbBudgetAlert;return <div><Tit>{t("s7t")}</Tit><p className="text-sm text-zinc-400 mb-4">{t("s7d")} <a href="https://console.firebase.google.com" target="_blank" rel="noreferrer" className="text-blue-400 underline">Firebase Console ↗</a></p><div className="space-y-2"><Chk checked={s.fbProjectCreated} onChange={v=>u({fbProjectCreated:v})}><strong>{t("s7c1")}</strong> — {t("s7c1d")} <code className="bg-zinc-700 px-1 rounded text-blue-300">{s.slug}</code> {t("s7c1d2")}</Chk><Chk checked={s.fbBlazeUpgraded} onChange={v=>u({fbBlazeUpgraded:v})}><strong>{t("s7c2")}</strong> — {t("s7c2d")}</Chk><Chk checked={s.fbBudgetAlert} onChange={v=>u({fbBudgetAlert:v})}><strong>{t("s7c3")}</strong> — {t("s7c3d")}</Chk></div><Nav onBack={()=>goTo(6)} onNext={()=>goTo(8)} nextDisabled={!ok} t={t}/></div>}

function StepList({items}){return <ol className="mt-2 ml-1 space-y-1">{items.map((s,i)=> <li key={i} className="text-xs text-zinc-400 flex gap-2"><span className="text-blue-400 font-mono flex-shrink-0">{i+1}.</span><span>{s}</span></li>)}</ol>}
function S8({s,u,t,goTo}){const ok=s.svcAuth&&s.svcFirestore&&s.svcHostingWeb&&s.svcFunctions;return <div><Tit>{t("s8t")}</Tit><p className="text-sm text-zinc-400 mb-4">{t("s8d")}</p><div className="space-y-3"><Chk checked={s.svcAuth} onChange={v=>u({svcAuth:v})}><strong>{t("s8a")}</strong><StepList items={t("s8as")||[]}/></Chk><Chk checked={s.svcFirestore} onChange={v=>u({svcFirestore:v})}><strong>{t("s8f")}</strong><StepList items={t("s8fs")||[]}/></Chk><Chk checked={s.svcHostingWeb} onChange={v=>u({svcHostingWeb:v})}><strong>{t("s8h")}</strong><StepList items={t("s8hs")||[]}/></Chk><Chk checked={s.svcFunctions} onChange={v=>u({svcFunctions:v})}><strong>{t("s8fn")}</strong><StepList items={t("s8fns")||[]}/></Chk></div><Nav onBack={()=>goTo(7)} onNext={()=>goTo(9)} nextDisabled={!ok} t={t}/></div>}

function S9({s,u,t,goTo}){const f=k=>s[k]||"";const errs={};if(f("fbApiKey")&&f("fbApiKey").length<10)errs.k="Too short";if(f("fbAuthDomain")&&!f("fbAuthDomain").includes(".firebaseapp.com"))errs.d="\u2192 .firebaseapp.com";if(f("fbStorageBucket")&&!f("fbStorageBucket").includes(".appspot.com")&&!f("fbStorageBucket").includes(".firebasestorage.app"))errs.sb="\u2192 .appspot.com / .firebasestorage.app";if(f("fbMessagingSenderId")&&!/^\d{8,}$/.test(f("fbMessagingSenderId")))errs.m="Numeric, 8+ digits";if(f("fbAppId")&&!f("fbAppId").startsWith("1:"))errs.a="\u2192 1:...";const allF=f("fbApiKey")&&f("fbAuthDomain")&&f("fbProjectId")&&f("fbStorageBucket")&&f("fbMessagingSenderId")&&f("fbAppId");const ok=allF&&!errs.k&&!errs.d&&!errs.m;return <div><Tit>{t("s9t")}</Tit><div className="bg-zinc-800/80 border border-zinc-700 rounded-xl p-4 mb-4"><StepList items={t("s9steps")||[]}/></div><Inp label="apiKey" value={f("fbApiKey")} error={errs.k} mono placeholder="AIzaSy..." onChange={e=>u({fbApiKey:e.target.value})}/><Inp label="authDomain" value={f("fbAuthDomain")} error={errs.d} mono placeholder={`${s.slug}.firebaseapp.com`} onChange={e=>u({fbAuthDomain:e.target.value})}/><Inp label="projectId" value={f("fbProjectId")} mono placeholder={s.slug} onChange={e=>u({fbProjectId:e.target.value})}/><Inp label="storageBucket" value={f("fbStorageBucket")} error={errs.sb} mono placeholder={`${s.slug}.firebasestorage.app`} onChange={e=>u({fbStorageBucket:e.target.value})}/><Inp label="messagingSenderId" value={f("fbMessagingSenderId")} error={errs.m} mono placeholder="123456789012" onChange={e=>u({fbMessagingSenderId:e.target.value})}/><Inp label="appId" value={f("fbAppId")} error={errs.a} mono placeholder="1:123456789012:web:abc123" onChange={e=>u({fbAppId:e.target.value})}/><Nav onBack={()=>goTo(8)} onNext={()=>goTo(10)} nextDisabled={!ok} t={t}/></div>}
function S10({s,u,t,goTo}){const gcpSecretUrl=`https://console.cloud.google.com/apis/library/secretmanager.googleapis.com?project=${s.slug}`;const ok=s.cliInstalled&&s.cliLoggedIn&&s.cliProjectLinked&&s.cliSecretManagerEnabled&&s.cliSecretSaved;return <div><Tit>{t("s10t")}</Tit><p className="text-sm text-zinc-400 mb-2">{t("s10d")}</p><p className="text-xs text-amber-400/80 mb-4">{t("s10node")}</p><div className="space-y-2"><Chk checked={s.cliInstalled} onChange={v=>u({cliInstalled:v})}><strong>{t("s10c1")}</strong><br/><code className="text-xs bg-zinc-700 px-1.5 py-0.5 rounded block mt-1">npm install -g firebase-tools</code></Chk><Chk checked={s.cliLoggedIn} onChange={v=>u({cliLoggedIn:v})}><strong>{t("s10c2")}</strong><br/><code className="text-xs bg-zinc-700 px-1.5 py-0.5 rounded block mt-1">firebase login</code><span className="text-xs text-amber-400/80 block mt-0.5">{t("s10c2w")}</span></Chk><Chk checked={s.cliProjectLinked} onChange={v=>u({cliProjectLinked:v})}><strong>{t("s10c3")}</strong><br/><code className="text-xs bg-zinc-700 px-1.5 py-0.5 rounded block mt-1">firebase use --add</code><span className="text-xs text-zinc-500 block mt-0.5">{t("s10c3d")} <code>{s.slug}</code>{t("s10c3d2")}</span></Chk><Chk checked={s.cliSecretManagerEnabled} onChange={v=>u({cliSecretManagerEnabled:v})}><strong>{t("s10c5")}</strong><br/><a href={gcpSecretUrl} target="_blank" rel="noreferrer" className="text-xs text-blue-400 underline block mt-1">Google Cloud Console → Secret Manager API ↗</a><span className="text-xs text-zinc-500 block mt-0.5">{t("s10c5d")}</span></Chk><Chk checked={s.cliSecretSaved} onChange={v=>u({cliSecretSaved:v})}><strong>{t("s10c4")}</strong><br/><code className="text-xs bg-zinc-700 px-1.5 py-0.5 rounded block mt-1">firebase functions:secrets:set GEMINI_API_KEY</code><span className="text-xs text-zinc-500 block mt-0.5">{t("s10c4d")}</span></Chk></div><Nav onBack={()=>goTo(9)} onNext={()=>goTo(11)} nextDisabled={!ok} t={t}/></div>}

function S11({s,t,goTo,onReset}){const[toast,setToast]=useState(null);const[tt,setTT]=useState("success");const[cr,setCR]=useState(false);const[sj,setSJ]=useState(false);const jr=useRef(null);const admins=s.authorizedUsers.filter(x=>x.role==="admin").length;const config={version:"v0.008",appName:s.appName,slug:s.slug,ownerEmail:s.ownerEmail,geminiApiKey:s.geminiApiKey,geminiModel:s.geminiModel,authorizedUsers:s.authorizedUsers.map(x=>({email:x.email.toLowerCase().trim(),role:x.role})),firestoreRegion:"eur3",functionsRegion:"europe-west1",firebaseConfig:{apiKey:s.fbApiKey,authDomain:s.fbAuthDomain,projectId:s.fbProjectId,storageBucket:s.fbStorageBucket,messagingSenderId:s.fbMessagingSenderId,appId:s.fbAppId}};const cs=JSON.stringify(config,null,2);const prompt=`Here's my complete suppa-agent configuration:\n\n${cs}\n\nGenerate all project files with REAL Firebase config values (no placeholders): package.json files (Node 22), vite configs, firebase.json, .firebaserc, firestore.rules, firestore.indexes.json (chats composite index: ownerId ASC + updatedAt DESC), web/ frontend (React + Vite), functions/index.js with Gemini (${s.geminiModel}, firebase-functions/v2 onCall), CLAUDE.md.\n\nCRITICAL post-deploy steps to include in CLAUDE.md:\n1. cd web && npm install && cd ../functions && npm install && cd ..\n2. firebase deploy\n3. Open the app URL — you will see a Firestore index error. Click the error link to create the composite index. Wait 2-3 minutes.\n4. Go to Google Cloud Console → Cloud Run. For each service (chatWithGemini, healthCheck): click the service → Security tab → add 'allUsers' as 'Cloud Run Invoker' role. This is required because Gen 2 Cloud Functions run on Cloud Run.\n5. Go to Firebase Console → Firestore → create document: collection 'authorizedUsers', document ID '${s.ownerEmail}', field 'role' = 'admin'. This authorizes the first admin.\n6. Reload the app, log in with ${s.ownerEmail}, send a test message.\n\nDeliver as zip with Claude Code commands. Start with the project structure overview.`;const flash=(m,ty="success")=>{setToast(m);setTT(ty);setTimeout(()=>setToast(null),4e3)};const handleSend=()=>{try{if(typeof sendPrompt==="function"){sendPrompt(prompt);flash(t("sent"));return}}catch{}if(tryCopy(prompt))flash(t("copied"),"info");else{setSJ(true);flash(t("copy_fallback"),"info")}};const handleCopy=()=>{if(tryCopy(cs))flash(t("copied"));else{setSJ(true);flash(t("copy_fallback"),"info")}};return <div><Tit>{t("s11t")}</Tit><div className="bg-zinc-800/80 border border-zinc-700 rounded-xl overflow-hidden mb-4"><Row label={t("lb_app")} value={s.appName}/><Row label={t("lb_slug")} value={s.slug}/><Row label={t("lb_url")} value={`https://${s.slug}.web.app`}/><Row label={t("lb_owner")} value={s.ownerEmail}/><Row label={t("lb_gemini")} value={`${s.geminiModel} · AIza...${s.geminiApiKey.slice(-4)}`}/><Row label={t("lb_users")} value={`${s.authorizedUsers.length} (${admins} admin)`}/><Row label={t("lb_firebase")} value={`${s.fbProjectId} · Blaze ✓`}/><Row label={t("lb_services")} value="Auth · Firestore · Hosting · Functions ✓"/><Row label={t("lb_cli")} value="✓"/></div><div className="space-y-2.5"><Btn v="success" onClick={handleSend} className="w-full">{t("send")}</Btn><Btn v="secondary" onClick={handleCopy} className="w-full">{t("copy")}</Btn>{!cr?<Btn v="danger" onClick={()=>setCR(true)} className="w-full">{t("reset")}</Btn>:<div className="bg-zinc-900 border border-zinc-600 rounded-lg p-3 space-y-2"><p className="text-sm text-zinc-300">{t("confirm")}</p><div className="flex gap-2"><Btn v="danger" onClick={()=>{setCR(false);onReset()}} className="flex-1">{t("yes")}</Btn><Btn v="ghost" onClick={()=>setCR(false)} className="flex-1">{t("cancel")}</Btn></div></div>}</div><Toast message={toast} type={tt}/>{sj&&<div className="mt-3"><div className="flex justify-between mb-1"><span className="text-xs text-zinc-500">{t("copy_fallback")}</span><button onClick={()=>{jr.current?.select();jr.current?.focus()}} className="text-xs text-blue-400 cursor-pointer">{t("select_all")}</button></div><textarea ref={jr} readOnly value={cs} onClick={()=>jr.current?.select()} className="w-full h-40 px-3 py-2 bg-zinc-900 text-zinc-300 border border-zinc-700 rounded-lg font-mono text-xs resize-none"/></div>}{!sj&&<button onClick={()=>setSJ(true)} className="mt-3 text-xs text-zinc-600 hover:text-zinc-400 cursor-pointer">{t("show_json")}</button>}<Nav onBack={()=>goTo(10)} t={t} showBack/></div>}

// ─── Main ────────────────────────────────────────────
export default function Wizard(){const[state,setState]=useState(DEFAULT_STATE);const[hydrated,setHydrated]=useState(false);const[lang,setLang]=useState("en");const sv=useRef(null);
useEffect(()=>{Promise.all([loadState(),loadLang()]).then(([s,l])=>{if(s)setState(p=>({...p,...s}));setLang(l||detectLang());setHydrated(true)})},[]);
useEffect(()=>{if(!hydrated)return;if(sv.current)clearTimeout(sv.current);sv.current=setTimeout(()=>saveState(state),300);return()=>clearTimeout(sv.current)},[state,hydrated]);
const u=useCallback(p=>setState(x=>({...x,...p})),[]);const goTo=step=>u({step});const reset=async()=>{await clearState();setState({...DEFAULT_STATE})};
const t=k=>T[lang]?.[k]||T.en[k]||k;
if(!hydrated)return <div className="min-h-screen bg-zinc-950 flex items-center justify-center text-zinc-500 text-sm">{T[lang]?.loading||"Loading..."}</div>;
const S={1:<S1 t={t} goTo={goTo}/>,2:<S2 s={state} u={u} t={t} goTo={goTo}/>,3:<S3 s={state} u={u} t={t} goTo={goTo}/>,4:<S4 s={state} u={u} t={t} goTo={goTo}/>,5:<S5 s={state} u={u} t={t} goTo={goTo}/>,6:<S6 s={state} t={t} goTo={goTo}/>,7:<S7 s={state} u={u} t={t} goTo={goTo}/>,8:<S8 s={state} u={u} t={t} goTo={goTo}/>,9:<S9 s={state} u={u} t={t} goTo={goTo}/>,10:<S10 s={state} u={u} t={t} goTo={goTo}/>,11:<S11 s={state} t={t} goTo={goTo} onReset={reset}/>};
return <div className="min-h-screen bg-zinc-950 text-white"><div className="max-w-xl mx-auto px-4 py-6"><div className="flex items-center justify-between mb-4"><ProgressBar step={state.step}/><LangSelect lang={lang} setLang={setLang}/></div>{S[state.step]||S[1]}</div></div>}
